    });
  });
});

const p = new Promise((resolve, reject) => {
  // 异步操作
  const ok = Math.random() > 0.5;
  setTimeout(() => {
    if (ok) resolve('成功数据');   // pending → fulfilled
    else   reject(new Error('失败原因')); // pending → rejected
  }, 1000);
});

p.then(v => console.log('成功:', v))
 .catch(e => console.log('失败:', e.message));

async function loadProfile(userId) {
  // 三个请求并行发出，全部成功才返回
  const [user, posts, friends] = await Promise.all([
    fetch(`/api/users/${userId}`).then(r => r.json()),
    fetch(`/api/posts?user=${userId}`).then(r => r.json()),
    fetch(`/api/friends?user=${userId}`).then(r => r.json()),
  ]);
  return { user, posts, friends };
}

function withTimeout(promise, ms) {
  const timeout = new Promise((_, reject) =>
    setTimeout(() => reject(new Error('超时')), ms)
  );
  return Promise.race([promise, timeout]);
}

// 5 秒内没返回就超时
const data = await withTimeout(fetch(url), 5000);

// ❌ 错误：忘记 return
getUser().then(user => {
  getPosts(user.id);  // 没有 return！
}).then(posts => {
  console.log(posts);  // undefined！
});

// ✅ 正确：return Promise
getUser().then(user => {
  return getPosts(user.id);
}).then(posts => {
  console.log(posts);  // posts 数组
});

// ❌ 串行：每个请求等前一个完成
for (const url of urls) {
  await fetch(url);  // 10 个 URL = 10 倍时间
}

// ✅ 并行：所有请求同时发出
await Promise.all(urls.map(url => fetch(url)));

